// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract BadgeManager {

    // ── Định nghĩa tất cả loại nhãn ───────────────────────────
    enum BadgeType {
        // Nhãn xấu — Worker
        ABANDONED_JOB,           // 0: nhận job rồi không start / không submit
        BAD_RATING,              // 1: bị đánh giá 1-2 sao
        LOST_DISPUTE,            // 2: thua dispute
        VOTED_WRONG,             // 3: voter bỏ phiếu sai
        RAGE_QUIT,               // 4: thoát job giữa chừng

        // Nhãn xấu — Client
        IGNORED_SUBMISSION,      // 5: không phản hồi sau worker submit
        CHANGED_TERMS,           // 6: thay đổi điều khoản giữa chừng
        LOST_DISPUTE_CLIENT,     // 7: thua dispute (phía client)
        SERIAL_CANCELLER,        // 8: hủy job nhiều lần sau khi có worker nhận
        SCAM_LABEL,              // 9: đủ điều kiện bị gán nhãn scam

        // Nhãn tốt — hiển thị thành tích
        TOP_WORKER,              // 10: hoàn thành nhiều job, rating cao
        RELIABLE_CLIENT,         // 11: luôn approve đúng hạn, không dispute
        TRUSTED_VOTER            // 12: vote đúng nhiều lần
    }

    // ── Struct lưu từng badge ──────────────────────────────────
    struct Badge {
        BadgeType badgeType;
        uint256   jobId;       // job liên quan (0 nếu không liên quan job cụ thể)
        uint256   timestamp;
        string    note;        // mô tả ngắn
    }

    // address → danh sách badge
    mapping(address => Badge[]) private _badges;

    // Đếm nhanh theo loại — để check ngưỡng mà không loop
    // address => BadgeType => count
    mapping(address => mapping(uint256 => uint256)) public badgeCount;

    // ── Ngưỡng tự động leo thang ──────────────────────────────
    uint256 public constant SERIAL_CANCEL_THRESHOLD = 3;  // hủy 3 job có worker → SERIAL_CANCELLER
    uint256 public constant SCAM_THRESHOLD          = 5;  // hủy 5 job có worker → SCAM_LABEL

    // ── Events ────────────────────────────────────────────────
    event BadgeAwarded(address indexed user, BadgeType indexed badgeType, uint256 jobId);

    // ── Internal: gán nhãn ────────────────────────────────────
    function _addBadge(
        address   user,
        BadgeType badgeType,
        uint256   jobId
    ) internal {
        string memory note = _badgeNote(badgeType);

        _badges[user].push(Badge({
            badgeType: badgeType,
            jobId:     jobId,
            timestamp: block.timestamp,
            note:      note
        }));

        badgeCount[user][uint256(badgeType)] += 1;

        emit BadgeAwarded(user, badgeType, jobId);
    }

    // ── Internal: logic kiểm tra serial cancel + scam ─────────
    function _recordClientCancel(address client, uint256 jobId) internal {
        // Mỗi lần client hủy job đã có worker → tăng đếm
        _addBadge(client, BadgeType.SERIAL_CANCELLER, jobId);

        uint256 cancelCount = badgeCount[client][uint256(BadgeType.SERIAL_CANCELLER)];

        // Leo thang: đủ ngưỡng → SCAM_LABEL
        if (cancelCount >= SCAM_THRESHOLD) {
            // Chỉ thêm SCAM_LABEL lần đầu
            if (badgeCount[client][uint256(BadgeType.SCAM_LABEL)] == 0) {
                _addBadge(client, BadgeType.SCAM_LABEL, 0);
            }
        }
    }

    // ── View: lấy toàn bộ badge của 1 address ─────────────────
    function getBadges(address user)
        external view
        returns (
            BadgeType[] memory types,
            uint256[]   memory jobIds,
            uint256[]   memory timestamps,
            string[]    memory notes
        )
    {
        Badge[] storage bs = _badges[user];
        uint256 len = bs.length;

        types      = new BadgeType[](len);
        jobIds     = new uint256[](len);
        timestamps = new uint256[](len);
        notes      = new string[](len);

        for (uint256 i = 0; i < len; i++) {
            types[i]      = bs[i].badgeType;
            jobIds[i]     = bs[i].jobId;
            timestamps[i] = bs[i].timestamp;
            notes[i]      = bs[i].note;
        }
    }

    // View: đếm badge theo loại
    function getBadgeCount(address user, BadgeType badgeType)
        external view returns (uint256)
    {
        return badgeCount[user][uint256(badgeType)];
    }

    // View: kiểm tra nhanh có nhãn scam không
    function isScammer(address user) public view returns (bool) {
        return badgeCount[user][uint256(BadgeType.SCAM_LABEL)] > 0;
    }

    // ── Internal: note mô tả cho từng loại ───────────────────
    function _badgeNote(BadgeType t) private pure returns (string memory) {
        if (t == BadgeType.ABANDONED_JOB)         return "Accepted or in-progress job abandoned";
        if (t == BadgeType.BAD_RATING)             return "Received 1 or 2 star rating";
        if (t == BadgeType.LOST_DISPUTE)           return "Lost a dispute";
        if (t == BadgeType.VOTED_WRONG)            return "Voted for the losing side in dispute";
        if (t == BadgeType.RAGE_QUIT)              return "Rage quit a job";
        if (t == BadgeType.IGNORED_SUBMISSION)     return "Did not respond after worker submitted";
        if (t == BadgeType.CHANGED_TERMS)          return "Reported for changing job terms";
        if (t == BadgeType.LOST_DISPUTE_CLIENT)    return "Lost a dispute as client";
        if (t == BadgeType.SERIAL_CANCELLER)       return "Cancelled job after worker accepted";
        if (t == BadgeType.SCAM_LABEL)             return "Flagged as potential scammer";
        if (t == BadgeType.TOP_WORKER)             return "Consistently high-rated worker";
        if (t == BadgeType.RELIABLE_CLIENT)        return "Reliable client with clean history";
        if (t == BadgeType.TRUSTED_VOTER)          return "Trusted dispute voter";
        return "";
    }
}

contracts/DisputeManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./GigStructs.sol";
import "./VoterSelector.sol";

contract DisputeManager is VoterSelector {

    // ── Storage ────────────────────────────────────────────────
    uint256 public constant VOTE_DURATION = 300; // 5 phút (đơn vị hiện là giây)
    // Để test trên Remix đổi thành: uint256 public constant VOTE_DURATION = 300; // 5 phút

    // Lưu dispute theo jobId
    // Dùng struct riêng không có mapping bên trong để tránh lỗi
    struct DisputeData {
        uint256 jobId;
        address initiator;
        string  evidenceHash;     // bằng chứng bên khởi tạo
        string  counterHash;      // bằng chứng bên kia phản hồi
        address[5] voters;        // 5 voter
        uint8   voterCount;       // thực tế có bao nhiêu voter (có thể < 5)
        uint8   votesForWorker;
        uint8   votesForClient;
        uint256 deadline;
        bool    resolved;
        DisputeOutcome outcome;
    }

    mapping(uint256 => DisputeData)              public  disputes;
    mapping(uint256 => mapping(address => bool)) public  hasVoted;
    // jobId => voter address => true/false (vote cho worker hay client)
    mapping(uint256 => mapping(address => bool)) public  voteChoice;

    // ── Events ─────────────────────────────────────────────────
    event DisputeRaised(uint256 indexed jobId, address indexed initiator);
    event CounterEvidenceSubmitted(uint256 indexed jobId, address indexed responder);
    event VoterSelected(uint256 indexed jobId, address[] voters);
    event Voted(uint256 indexed jobId, address indexed voter, bool voteForWorker);
    event DisputeResolved(uint256 indexed jobId, DisputeOutcome outcome);
    event VotersReplaced(uint256 indexed jobId, address[] newVoters, uint256 newDeadline);

    // ── Bước 8: Raise dispute ───────────────────────────────────
    // Gọi từ GigStamp khi client hoặc worker muốn tranh chấp
    function _raiseDispute(
        uint256 jobId,
        address initiator,
        string memory evidenceHash,
        address jobClient,
        address jobWorker
    ) internal {
        DisputeData storage d = disputes[jobId];
        require(!d.resolved, "Already resolved");
        require(d.deadline == 0, "Dispute already raised"); // chưa có dispute

        d.jobId        = jobId;
        d.initiator    = initiator;
        d.evidenceHash = evidenceHash;
        d.deadline     = block.timestamp + VOTE_DURATION;

        // Bước 9: chọn voter ngay khi raise
        uint256 seed = uint256(
            keccak256(abi.encodePacked(block.timestamp, block.prevrandao, jobId))
        );

        address[] memory chosen = _selectVoters(jobClient, jobWorker, seed, 5);

        d.voterCount = uint8(chosen.length);
        for (uint8 i = 0; i < chosen.length; i++) {
            d.voters[i] = chosen[i];
        }

        emit DisputeRaised(jobId, initiator);
        emit VoterSelected(jobId, chosen);
    }

    // ── Bằng chứng phản hồi từ bên kia ────────────────────────
    function _submitCounter(
        uint256 jobId,
        address responder,
        address initiator,
        string memory counterHash
    ) internal {
        DisputeData storage d = disputes[jobId];
        require(d.deadline > 0, "No dispute");
        require(!d.resolved, "Already resolved");
        require(responder != initiator, "Cannot counter own dispute");
        require(bytes(d.counterHash).length == 0, "Counter already submitted");

        d.counterHash = counterHash;
        emit CounterEvidenceSubmitted(jobId, responder);
    }

    // ── Bước 10: Vote ──────────────────────────────────────────
    function _castVote(
        uint256 jobId,
        address voter,
        bool    voteForWorker
    ) internal {
        DisputeData storage d = disputes[jobId];
        require(d.deadline > 0,              "No dispute exists");
        require(!d.resolved,                 "Already resolved");
        require(block.timestamp < d.deadline,"Voting period ended");
        require(!hasVoted[jobId][voter],     "Already voted");

        // Kiểm tra voter có trong danh sách được chọn không
        bool isSelectedVoter = false;
        for (uint8 i = 0; i < d.voterCount; i++) {
            if (d.voters[i] == voter) {
                isSelectedVoter = true;
                break;
            }
        }
        require(isSelectedVoter, "Not a selected voter");

        hasVoted[jobId][voter]   = true;
        voteChoice[jobId][voter] = voteForWorker;

        if (voteForWorker) {
            d.votesForWorker++;
        } else {
            d.votesForClient++;
        }

        emit Voted(jobId, voter, voteForWorker);
    }

    // ── Bước 11: Resolve theo đa số ────────────────────────────
    // Trả về true nếu worker thắng
    function _resolveDispute(uint256 jobId) internal returns (DisputeOutcome outcome) {
        DisputeData storage d = disputes[jobId];
        require(d.deadline > 0,               "No dispute");
        require(!d.resolved,                  "Already resolved");
        require(
            block.timestamp >= d.deadline ||
            d.votesForWorker + d.votesForClient == d.voterCount,
            "Voting not ended"
        ); // resolve sớm nếu tất cả đã vote

        d.resolved  = true;
        
        if (d.votesForWorker == d.votesForClient) {
            outcome = DisputeOutcome.DRAW;
        } else if (d.votesForWorker > d.votesForClient) {
            outcome = DisputeOutcome.WORKER_WON;
        } else {
            outcome = DisputeOutcome.CLIENT_WON;
        }
        
        d.outcome = outcome;

        emit DisputeResolved(jobId, outcome);

        // Cập nhật score voter (Chỉ khi có người thắng rõ ràng)
        if (outcome != DisputeOutcome.DRAW) {
            bool workerWon = (outcome == DisputeOutcome.WORKER_WON);
            for (uint8 i = 0; i < d.voterCount; i++) {
                address v = d.voters[i];
                if (!hasVoted[jobId][v]) continue; 

                bool votedForWorker = voteChoice[jobId][v];
                bool votedCorrectly = (votedForWorker == workerWon);

                if (votedCorrectly) {
                    _addScore(v, 3, "voted_correctly");
                } else {
                    _subScore(v, 3, "voted_wrongly");
                }
            }
        }
    }

    // ── Bước 12: Thay thế voter không hoạt động ──────────────────
    function _replaceInactiveVoters(
        uint256 jobId,
        address jobClient,
        address jobWorker
    ) internal {
        DisputeData storage d = disputes[jobId];
        require(d.deadline > 0, "No dispute");
        require(!d.resolved, "Already resolved");
        require(block.timestamp >= d.deadline, "Deadline not passed");

        // Tìm danh sách voter chưa vote
        uint8 inactiveCount = 0;
        for (uint8 i = 0; i < d.voterCount; i++) {
            if (!hasVoted[jobId][d.voters[i]]) {
                inactiveCount++;
            }
        }
        require(inactiveCount > 0, "All selected voters have voted");

        // Tạo danh sách loại trừ: Client, Worker, và các voter ĐANG CÓ (để tránh chọn trùng chính họ)
        address[] memory excluded = new address[](2 + d.voterCount);
        excluded[0] = jobClient;
        excluded[1] = jobWorker;
        for (uint8 i = 0; i < d.voterCount; i++) {
            excluded[2 + i] = d.voters[i];
        }

        uint256 seed = uint256(keccak256(abi.encodePacked(block.timestamp, jobId, inactiveCount)));
        address[] memory newSelected = _selectVotersExtended(excluded, seed, inactiveCount);

        // Thay thế các voter chưa vote bằng voter mới
        uint8 substituted = 0;
        for (uint8 i = 0; i < d.voterCount; i++) {
            if (!hasVoted[jobId][d.voters[i]] && substituted < newSelected.length) {
                d.voters[i] = newSelected[substituted];
                substituted++;
            }
        }

        // Reset deadline
        d.deadline = block.timestamp + VOTE_DURATION;
        
        emit VotersReplaced(jobId, newSelected, d.deadline);
        emit VoterSelected(jobId, _getVotersArray(d)); // Thông báo lại danh sách mới
    }

    // Helper to get memory array from storage fixed array
    function _getVotersArray(DisputeData storage d) internal view returns (address[] memory) {
        address[] memory v = new address[](d.voterCount);
        for (uint8 i = 0; i < d.voterCount; i++) {
            v[i] = d.voters[i];
        }
        return v;
    }

    // ── View helpers ───────────────────────────────────────────
    function getDisputeVoters(uint256 jobId) external view returns (address[5] memory) {
        return disputes[jobId].voters;
    }

    function getVoteCount(uint256 jobId) external view returns (uint8 forWorker, uint8 forClient) {
        DisputeData storage d = disputes[jobId];
        return (d.votesForWorker, d.votesForClient);
    }
}

contracts/GigStamp.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./Auth.sol";
import "./GigStructs.sol";
import "./DisputeManager.sol";
import "./BadgeManager.sol";

contract GigStamp is Auth, DisputeManager, BadgeManager {

    // STORAGE
    uint256 public jobCount;

    mapping(uint256 => Job) public jobs;

    // 1. CREATE JOB (CLIENT ONLY)
    function createJob(
        string memory _jobHash,
        uint256 _pay,
        uint256 _startTime,
        uint256 _endTime,
        uint256 _tolerance
    ) external {

        require(roles[msg.sender] == Role.CLIENT, "Not client");

        jobs[jobCount] = Job({
            client: msg.sender,
            worker: address(0),

            pay: _pay,

            startTime: _startTime,
            endTime: _endTime,
            tolerance: _tolerance,
            
            jobHash: _jobHash,
            resultHash: "",

            status: JobStatus.CREATED,

            fundedAt: 0,
            acceptedAt: 0,
            submittedAt: 0
        });

        jobCount++;
    }

    // 2. FUND JOB
    function fundJob(uint256 jobId) external payable {
        Job storage job = jobs[jobId];

        require(roles[msg.sender] == Role.CLIENT, "Not client");
        require(msg.sender == job.client, "Not owner");
        require(job.status == JobStatus.CREATED, "Not Created");

        require(msg.value == job.pay, "Wrong amount");
        
        job.fundedAt = block.timestamp; // ghi lại thời điểm nạp tiền
        
        job.status = JobStatus.FUNDED;
    }

    // 3. ACCEPT JOB
    function acceptJob(uint256 jobId) external {
        Job storage job = jobs[jobId];

        require(roles[msg.sender] == Role.WORKER, "Not worker");
        require(job.status == JobStatus.FUNDED, "Not funded");
        require(msg.sender != job.client, "Cannot take own job");
        require(job.worker == address(0), "Already taken");
        require(
            block.timestamp <= job.startTime + job.tolerance,
            "Start window expired"
        );

        job.worker = msg.sender;
        job.acceptedAt = block.timestamp;

        job.status = JobStatus.ACCEPTED;
    }

    // Start
    function startWork(uint256 jobId) external {
    Job storage job = jobs[jobId];
    require(msg.sender == job.worker,          "Not worker");
    require(job.status == JobStatus.ACCEPTED,  "Not accepted");
    require(
        block.timestamp <= job.startTime + job.tolerance,
        "Start window expired"
    );

    job.status = JobStatus.IN_PROGRESS;
    }

    // Timeout: worker accept nhưng không start trong thời gian cho phép
    function cancelIfNotStarted(uint256 jobId) external {
        Job storage job = jobs[jobId];
        require(job.status == JobStatus.ACCEPTED, "Not accepted");
        require(
            block.timestamp > job.startTime + job.tolerance,
            "Too early"
        );

        job.status = JobStatus.CANCELLED; // Hủy
        address oldWorker  = job.worker;
        (bool ok, ) = job.client.call{value: job.pay}("");
        require(ok, "Refund failed");

        // Phạt worker nhận rồi bỏ
        _subScore(oldWorker, 5, "worker_accepted_not_started");
        _addBadge(oldWorker, BadgeType.ABANDONED_JOB, jobId);
    }

    // 4. SUBMIT WORK
    function submitWork(uint256 jobId, string memory _resultHash) external {
        Job storage job = jobs[jobId];

        require(msg.sender == job.worker, "Not worker");
        require(job.status == JobStatus.IN_PROGRESS, "Invalid state");
        require(
            block.timestamp <= job.endTime + job.tolerance,
            "Submit window expired"
        );

        job.resultHash = _resultHash;
        job.submittedAt  = block.timestamp;
        job.status = JobStatus.SUBMITTED;
    }

    // FEEDBACK STORAGE
    mapping(uint256 => Feedback) public feedbacks; // jobId → feedback

    // WORKER RATING
    mapping(address => uint256) public totalRating; // tổng sao
    mapping(address => uint256) public ratingCount; // số lần được đánh giá

    // 5. APPROVE & PAY & FEEDBACK
    function approveJob(uint256 jobId, uint8 _rating, string memory _comment) external {
        Job storage job = jobs[jobId];

        require(msg.sender == job.client, "Not client");
        require(job.status == JobStatus.SUBMITTED, "Not submitted");

        require(_rating >= 1 && _rating <= 5, "Invalid rating");

        job.status = JobStatus.COMPLETED;

        _addBadge(job.client, BadgeType.RELIABLE_CLIENT, jobId);

        // Score cho client khi approve
        _addScore(msg.sender, 5, "client_approved_job");

        // Score cho worker theo rating
        if (_rating >= 4) {
            _addScore(job.worker, 10, "job_completed");   // hoàn thành job
            _addScore(job.worker, 5,  "good_rating");     // rating tốt
        } else if (_rating <= 2) {
            _addScore(job.worker, 10, "job_completed");   // vẫn hoàn thành job
            _subScore(job.worker, 7,  "bad_rating");      // nhưng rating xấu
            _addBadge(job.worker, BadgeType.BAD_RATING, jobId);
        } else {
            // rating = 3: neutral
            _addScore(job.worker, 10, "job_completed");
        }

        // Lưu Feedback
        feedbacks[jobId] = Feedback({
            client: msg.sender,
            worker: job.worker,
            rating: _rating,
            comment: _comment
        });

        // Update Rating Worker
        totalRating[job.worker] += _rating;
        ratingCount[job.worker] += 1;

        // Pay        
        (bool success, ) = job.worker.call{value: job.pay}("");
        require(success, "Transfer failed");
    }

    // 6. REFUND IF NOT ACCEPTED
    
    function cancelJob(uint256 jobId) external {
        Job storage job = jobs[jobId];
        require(msg.sender == job.client, "Not client");

        // ── Trường hợp 0: CREATED, chưa nạp tiền
        if (job.status == JobStatus.CREATED) {
            job.status = JobStatus.CANCELLED;
            return;
        }

        // ── Trường hợp 1: FUNDED, chưa ai nhận
        if (job.status == JobStatus.FUNDED) {
            job.status = JobStatus.CANCELLED;
            _payout(job.client, job.pay);
            return;
        }

        // ── Trường hợp 2: ACCEPTED, worker đã nhận nhưng chưa start ──
        // Client được quyền hủy BẤT CỨ LÚC NÀO trong giai đoạn này
        if (job.status == JobStatus.ACCEPTED) {
            job.status = JobStatus.CANCELLED;

            // Ghi nhận hành vi client hủy sau khi có worker → scam check
            _recordClientCancel(job.client, jobId);

            // Worker bị hủy ngang không lỗi → không phạt, thậm chí bồi thường nhỏ
            // Trả lại toàn bộ tiền cho client (worker chưa làm gì)
            _payout(job.client, job.pay);

            // Nhưng ghi nhận để worker biết client này hay cancel
            _addBadge(job.client, BadgeType.SERIAL_CANCELLER, jobId);
            return;
        }

        revert("Cannot cancel at this stage");
    }

    // Helper tránh lặp code transfer
    function _payout(address to, uint256 amount) internal {
        (bool ok, ) = to.call{value: amount}("");
        require(ok, "Transfer failed");
    }

    // 7. GET AVERAGE RATING
    function getRating(address worker) public view returns (uint256) {
        if (ratingCount[worker] == 0) {
            return 0; // chưa có đánh giá
        }
        return totalRating[worker] / ratingCount[worker];
    }


    // 8. RAISE DISPUTE
    // Có thể gọi sau khi SUBMITTED hoặc sau COMPLETED (trong vòng X ngày)
    function raiseDispute(uint256 jobId, string memory evidenceHash) external {
        Job storage job = jobs[jobId];
        require(
            msg.sender == job.client || msg.sender == job.worker,
            "Not involved"
        );
        require(
            job.status == JobStatus.SUBMITTED ||
            job.status == JobStatus.IN_PROGRESS,
            "Invalid state for dispute"
        );

        job.status = JobStatus.DISPUTED;

        _raiseDispute(
            jobId,
            msg.sender,
            evidenceHash,
            job.client,
            job.worker
        );
    }

    // 8b. COUNTER EVIDENCE — bên kia nộp bằng chứng phản hồi
    function submitCounterEvidence(uint256 jobId, string memory counterHash) external {
        Job storage job = jobs[jobId];
        require(
            msg.sender == job.client || msg.sender == job.worker,
            "Not involved"
        );
        require(job.status == JobStatus.DISPUTED, "Not disputed");

        _submitCounter(
            jobId,
            msg.sender,
            disputes[jobId].initiator,
            counterHash
        );
    }

    // 10. VOTE — voter bỏ phiếu
    function castVote(uint256 jobId, bool voteForWorker) external {
        require(jobs[jobId].status == JobStatus.DISPUTED, "Not disputed");
        _castVote(jobId, msg.sender, voteForWorker);
    }

    // 10b. REPLACE INACTIVE VOTERS — thay thế voter không hoạt động sau deadline
    function replaceInactiveVoters(uint256 jobId) external {
        Job storage job = jobs[jobId];
        require(job.status == JobStatus.DISPUTED, "Not disputed");
        _replaceInactiveVoters(jobId, job.client, job.worker);
    }

    // 11. RESOLVE — ai cũng có thể trigger sau khi hết thời gian vote
    function resolveDispute(uint256 jobId) external {
        Job storage job = jobs[jobId];
        require(job.status == JobStatus.DISPUTED, "Not disputed");

        DisputeOutcome outcome = _resolveDispute(jobId);
        job.status     = JobStatus.RESOLVED;

        if (outcome == DisputeOutcome.WORKER_WON) {
            // Worker thắng: nhận tiền
            _subScore(job.client, 10, "lost_dispute");
            _addBadge(job.client, BadgeType.LOST_DISPUTE_CLIENT, jobId);

            _addScore(job.worker, 10, "won_dispute");
            
            (bool ok, ) = job.worker.call{value: job.pay}("");
            require(ok, "Transfer failed");
        } else if (outcome == DisputeOutcome.CLIENT_WON) {
            // Client thắng: nhận refund
            _subScore(job.worker, 10, "lost_dispute");
            _addBadge(job.worker, BadgeType.LOST_DISPUTE, jobId);

            _addScore(job.client, 10, "won_dispute");  
            (bool ok, ) = job.client.call{value: job.pay}("");
            require(ok, "Transfer failed");
        } else if (outcome == DisputeOutcome.DRAW) {
            // Hòa: Chia đôi tiền, không gán badge, không đổi score
            uint256 half = job.pay / 2;
            
            // Trả client
            (bool ok1, ) = job.client.call{value: half}("");
            require(ok1, "Transfer failed (client)");
            
            // Trả worker (phần còn lại để tránh lẻ wei)
            (bool ok2, ) = job.worker.call{value: job.pay - half}("");
            require(ok2, "Transfer failed (worker)");
        }
    }

    uint256 public constant APPROVE_TIMEOUT = 120;

    // ── TIMEOUT 2: Worker start nhưng không submit ─────────
    // Client hoặc bất kỳ ai trigger sau SUBMIT_TIMEOUT
    function cancelIfNotSubmitted(uint256 jobId) external {
        Job storage job = jobs[jobId];
        require(job.status == JobStatus.IN_PROGRESS, "Not in progress");
        require(
            block.timestamp >= job.endTime + job.tolerance,
            "Too early"
        );

        job.status = JobStatus.CANCELLED;

        // Phạt worker vì nhận job rồi bỏ
        _subScore(job.worker, 10, "worker_abandoned");
        _addBadge(job.worker, BadgeType.ABANDONED_JOB, jobId);

        // Refund client
        (bool ok, ) = job.client.call{value: job.pay}("");
        require(ok, "Refund failed");
    }

    // ── TIMEOUT 3: Worker submit nhưng client không phản hồi ──
    // tự động trả tiền cho worker
    function autoReleaseIfNotApproved(uint256 jobId) external {
        Job storage job = jobs[jobId];
        require(job.status == JobStatus.SUBMITTED, "Not submitted");
        require(
            block.timestamp >= job.submittedAt + APPROVE_TIMEOUT,
            "Too early"
        );

        job.status = JobStatus.COMPLETED;

        // Phạt client vì cố tình delay
        _subScore(job.client, 8, "client_ignored_submission");
        _addBadge(job.client, BadgeType.IGNORED_SUBMISSION, jobId);

        // Worker vẫn được cộng điểm hoàn thành (dù không có rating)
        _addScore(job.worker, 10, "job_completed_auto");

        // Trả tiền cho worker
        (bool ok, ) = job.worker.call{value: job.pay}("");
        require(ok, "Transfer failed");
    }
}

contracts/ReputationManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract ReputationManager {

    // ── Constants ──────────────────────────────────────
    uint8 public constant INIT_SCORE   = 100;
    uint8 public constant MAX_SCORE    = 100;
    uint8 public constant MIN_SCORE    = 0;
    uint8 public constant VOTER_THRESHOLD = 100; // cần ≥ 80 để được chọn làm voter

    // ── Storage ────────────────────────────────────────
    mapping(address => uint8)  public  reputationScore;
    mapping(address => bool)   private _initialized; // Địa chỉ đã được khởi tạo score hay chưa

    // ── Events ─────────────────────────────────────────
    event ScoreChanged(address indexed user, uint8 oldScore, uint8 newScore, string reason);
    event ScoreInitialized(address indexed user);

    // ── Internal: init khi user đăng ký ───────────────
    function _initScore(address user) internal {
        require(!_initialized[user], "Already initialized");
        reputationScore[user] = INIT_SCORE;
        _initialized[user]    = true;
        emit ScoreInitialized(user);
    }

    // ── Internal: cộng điểm (có cap MAX) ──────────────
    function _addScore(address user, uint8 delta, string memory reason) internal {
        uint8 old = reputationScore[user];
        uint8 next = (uint16(old) + delta > MAX_SCORE)
            ? MAX_SCORE
            : old + delta;
        reputationScore[user] = next;
        emit ScoreChanged(user, old, next, reason);
    }

    // ── Internal: trừ điểm (có floor MIN) ─────────────
    function _subScore(address user, uint8 delta, string memory reason) internal {
        uint8 old = reputationScore[user];
        uint8 next = (delta >= old) ? MIN_SCORE : old - delta;
        reputationScore[user] = next;
        emit ScoreChanged(user, old, next, reason);
    }

    // ── View: kiểm tra đủ uy tín làm voter ────────────
    function isEligibleVoter(address user) public view returns (bool) {
        return reputationScore[user] >= VOTER_THRESHOLD;
    }
}

contracts/VoterSelector.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./ReputationManager.sol";

contract VoterSelector is ReputationManager {

    // Danh sách toàn bộ user đã đăng ký (thêm vào khi register)
    address[] internal _allUsers;

    // Tránh thêm trùng
    mapping(address => bool) private _isRegistered;

    // Gọi từ Auth khi register
    function _registerUser(address user) internal {
        if (!_isRegistered[user]) {
            _allUsers.push(user);
            _isRegistered[user] = true;
        }
    }

    // Chọn tối đa maxCount voter đủ điều kiện, loại trừ 2 bên tranh chấp
    function _selectVoters(
        address excludeA,   // client của job
        address excludeB,   // worker của job
        uint256 seed,       // số ngẫu nhiên seed (từ block data)
        uint8   maxCount    // thường là 5
    ) internal view returns (address[] memory) {

        // Bước 1: lọc danh sách eligible
        address[] memory pool = new address[](_allUsers.length);
        uint256 poolSize = 0;

        for (uint256 i = 0; i < _allUsers.length; i++) {
            address u = _allUsers[i];
            if (
                u != excludeA &&
                u != excludeB &&
                isEligibleVoter(u)   // score >= 80, từ ReputationManager
            ) {
                pool[poolSize] = u;
                poolSize++;
            }
        }

        // Bước 2: xác định số voter thực tế có thể chọn
        uint8 count = poolSize < maxCount
            ? uint8(poolSize)
            : maxCount;

        // BẮT BUỘC: Đảm bảo số voter là số lẻ để tránh hòa
        if (count > 0 && count % 2 == 0) {
            count--;
        }

        address[] memory selected = new address[](count);

        // Bước 3: Fisher-Yates shuffle đơn giản dựa trên seed
        // Tạo bản copy để shuffle không ảnh hưởng pool gốc
        address[] memory shuffled = new address[](poolSize);
        for (uint256 i = 0; i < poolSize; i++) {
            shuffled[i] = pool[i];
        }

        for (uint256 i = 0; i < count; i++) {
            uint256 j = i + (uint256(keccak256(abi.encodePacked(seed, i))) % (poolSize - i));
            // swap
            address tmp  = shuffled[i];
            shuffled[i]  = shuffled[j];
            shuffled[j]  = tmp;
            selected[i]  = shuffled[i];
        }

        return selected;
    }

    // Chọn voter với danh sách loại trừ động (Client, Worker, và các voter đã có)
    function _selectVotersExtended(
        address[] memory excluded,
        uint256 seed,
        uint8 countToSelect
    ) internal view returns (address[] memory) {
        address[] memory pool = new address[](_allUsers.length);
        uint256 poolSize = 0;

        for (uint256 i = 0; i < _allUsers.length; i++) {
            address u = _allUsers[i];
            bool isExcluded = false;
            for (uint256 j = 0; j < excluded.length; j++) {
                if (u == excluded[j]) {
                    isExcluded = true;
                    break;
                }
            }

            if (!isExcluded && isEligibleVoter(u)) {
                pool[poolSize] = u;
                poolSize++;
            }
        }

        uint8 finalCount = poolSize < countToSelect ? uint8(poolSize) : countToSelect;
        // Đảm bảo số lẻ (nếu cần - tùy thuộc logic gọi nhưng _selectVotersExtended thường dùng để Replace)
        // Tuy nhiên Dispute chính yêu cầu số lẻ, nên nếu Replace để bù đắp, tổng số vẫn nên là lẻ.
        
        address[] memory selected = new address[](finalCount);
        address[] memory shuffled = new address[](poolSize);
        for (uint256 i = 0; i < poolSize; i++) shuffled[i] = pool[i];

        for (uint256 i = 0; i < finalCount; i++) {
            uint256 j = i + (uint256(keccak256(abi.encodePacked(seed, i))) % (poolSize - i));
            address tmp = shuffled[i];
            shuffled[i] = shuffled[j];
            shuffled[j] = tmp;
            selected[i] = shuffled[i];
        }

        return selected;
    }
}
